function createDefaultVoxelStamp(stamp: DefaultVoxelStampTemplate): VoxelTerrain {
	return {
		Id: crypto.randomUUID(),
		Name: stamp.Name,
		Width: stamp.Width,
		Length: stamp.Length,
		Height: stamp.Height,
		Resolution: stamp.Resolution,
		Voxels: stamp.Voxels,
		VoxelsLoaded: true,
		Lighting: createDefaultVoxelTerrainLighting(),
		Background: createDefaultVoxelTerrainBackground(),
		Tags: [...stamp.Tags],
	};
}

export function getDefaultVoxelStampTemplateId(
	terrain: Pick<VoxelTerrain, "Tags">
): string | null {
	const tag = terrain.Tags?.find((candidate) =>
		candidate.startsWith(DEFAULT_VOXEL_STAMP_BUILTIN_ID_PREFIX)
	);
	return tag?.slice(DEFAULT_VOXEL_STAMP_BUILTIN_ID_PREFIX.length) ?? null;
}

export function createDefaultVoxelStamps(
	existingTemplateIds: ReadonlySet<string> = new Set()
): VoxelTerrain[] {
	return DEFAULT_VOXEL_STAMP_TEMPLATES
		.filter((stamp) => !existingTemplateIds.has(stamp.TemplateId))
		.map(createDefaultVoxelStamp);
}

export function addMissingDefaultVoxelStamps(campaign: {
	VoxelTerrains?: VoxelTerrain[];
}): number {
	campaign.VoxelTerrains ??= [];
	const existingTemplateIds = new Set<string>();
	for (const terrain of campaign.VoxelTerrains) {
		const templateId = getDefaultVoxelStampTemplateId(terrain);
		if (templateId) existingTemplateIds.add(templateId);
	}

	const missing = createDefaultVoxelStamps(existingTemplateIds);
	campaign.VoxelTerrains.push(...missing);
	return missing.length;
}
